def validate_object_id(func):
    @wraps(func)
    def wrapper(*args, **kwargs):
        user_id = kwargs.get('user_id') or request.view_args.get('user_id')
        doc_id = kwargs.get('doc_id') or request.view_args.get('doc_id')
        
        if user_id and not ObjectId.is_valid(user_id):
            return jsonify({'error': 'Invalid user ID format'}), 400
        if doc_id and not ObjectId.is_valid(doc_id):
            return jsonify({'error': 'Invalid document ID format'}), 400
        
        return func(*args, **kwargs)
    return wrapper

