@app.route('/documents', methods=['GET'])
def query_documents():
    try:
        user_id = request.args.get('user_id')
        status = request.args.get('status')
        tag = request.args.get('tag')
        search = request.args.get('search')
        limit = int(request.args.get('limit', 10))
        skip = int(request.args.get('skip', 0))
        
        query = {}
        
        if user_id:
            if not ObjectId.is_valid(user_id):
                return jsonify({'error': 'Invalid user_id format'}), 400
            query['user_id'] = user_id
        
        if status:
            query['status'] = status
        
        if tag:
            query['tags'] = tag
        
        if search:
            query['$text'] = {'$search': search}
        
        documents = list(documents_collection.find(query).limit(limit).skip(skip).sort('created_at', -1))
        
        for doc in documents:
            doc['_id'] = str(doc['_id'])
        
        return jsonify({'documents': documents, 'count': len(documents)}), 200
    
    except Exception as e:
        return jsonify({'error': f'Failed to query documents: {str(e)}'}), 500

