@app.route('/analytics/user-stats', methods=['GET'])
def user_statistics():
    try:
        pipeline = [
            {
                '$group': {
                    '_id': '$user_id',
                    'total_documents': {'$sum': 1},
                    'draft_count': {
                        '$sum': {'$cond': [{'$eq': ['$status', 'draft']}, 1, 0]}
                    },
                    'published_count': {
                        '$sum': {'$cond': [{'$eq': ['$status', 'published']}, 1, 0]}
                    },
                    'last_document': {'$max': '$created_at'}
                }
            },
            {
                '$lookup': {
                    'from': 'users',
                    'let': {'user_id_str': '$_id'},
                    'pipeline': [
                        {
                            '$match': {
                                '$expr': {
                                    '$eq': [{'$toString': '$_id'}, '$$user_id_str']
                                }
                            }
                        }
                    ],
                    'as': 'user_info'
                }
            },
            {
                '$unwind': {
                    'path': '$user_info',
                    'preserveNullAndEmptyArrays': True
                }
            },
            {
                '$project': {
                    'user_id': '$_id',
                    'username': '$user_info.username',
                    'email': '$user_info.email',
                    'total_documents': 1,
                    'draft_count': 1,
                    'published_count': 1,
                    'last_document': 1
                }
            },
            {
                '$sort': {'total_documents': -1}
            }
        ]
        
        stats = list(documents_collection.aggregate(pipeline))
        
        return jsonify({'user_statistics': stats}), 200
    
    except Exception as e:
        return jsonify({'error': f'Failed to generate statistics: {str(e)}'}), 500

@app.route('/analytics/tag-distribution', methods=['GET'])
def tag_distribution():
    try:
        pipeline = [
            {'$unwind': '$tags'},
            {
                '$group': {
                    '_id': '$tags',
                    'count': {'$sum': 1},
                    'documents': {'$push': '$title'}
                }
            },
            {'$sort': {'count': -1}},
            {'$limit': 20}
        ]
        
        distribution = list(documents_collection.aggregate(pipeline))
        
        return jsonify({'tag_distribution': distribution}), 200
    
    except Exception as e:
        return jsonify({'error': f'Failed to generate tag distribution: {str(e)}'}), 500

@app.route('/analytics/activity-timeline', methods=['GET'])
def activity_timeline():
    try:
        pipeline = [
            {
                '$group': {
                    '_id': {
                        'year': {'$year': '$created_at'},
                        'month': {'$month': '$created_at'},
                        'day': {'$dayOfMonth': '$created_at'}
                    },
                    'document_count': {'$sum': 1},
                    'statuses': {'$push': '$status'}
                }
            },
            {
                '$project': {
                    'date': {
                        '$dateFromParts': {
                            'year': '$_id.year',
                            'month': '$_id.month',
                            'day': '$_id.day'
                        }
                    },
                    'document_count': 1,
                    'statuses': 1
                }
            },
            {'$sort': {'date': -1}},
            {'$limit': 30}
        ]
        
        timeline = list(documents_collection.aggregate(pipeline))
        
        for item in timeline:
            item['date'] = item['date'].isoformat()
        
        return jsonify({'activity_timeline': timeline}), 200
    
    except Exception as e:
        return jsonify({'error': f'Failed to generate activity timeline: {str(e)}'}), 500

